@Service
public class CheckoutSaga {
    public void execute(CheckoutRequest req) {
        SagaState state = new SagaState();
        try {
            inventory.reserve(req); state.mark(INVENTORY_RESERVED);
            payment.charge(req);    state.mark(PAYMENT_CHARGED);
        } catch (Exception e) {
            compensate(state, req);
        }
    }
    private void compensate(SagaState state, CheckoutRequest req) {
        if (state.is(PAYMENT_CHARGED)) payment.refund(req);
        if (state.is(INVENTORY_RESERVED)) inventory.release(req);
    }
}

import java.util.*;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

public enum SagaStep {
    INVENTORY_RESERVED, ORDER_CREATED, PAYMENT_CHARGED, NOTIFICATION_SENT
}

public class SagaState {
    private final Set<SagaStep> completed = new LinkedHashSet<>(); // ordered
    private final String sagaId;
    private String status = "IN_PROGRESS";

    public SagaState(String sagaId) { this.sagaId = sagaId; }

    public void mark(SagaStep step) { completed.add(step); }
    public boolean is(SagaStep step) { return completed.contains(step); }
    public Set<SagaStep> getCompletedSteps() { return Collections.unmodifiableSet(completed); }
    public void setStatus(String s) { this.status = s; }
    public String getStatus() { return status; }
    public String getSagaId() { return sagaId; }
}

@SpringBootTest
class SagaStateTest {
    @Test void mark_and_check(){
        SagaState state = new SagaState("SAGA-001");
        state.mark(SagaStep.INVENTORY_RESERVED);
        state.mark(SagaStep.ORDER_CREATED);

        assertTrue(state.is(SagaStep.INVENTORY_RESERVED));
        assertTrue(state.is(SagaStep.ORDER_CREATED));
        assertFalse(state.is(SagaStep.PAYMENT_CHARGED));
        assertEquals(2, state.getCompletedSteps().size());
    }
    @Test void status_transitions(){
        SagaState state = new SagaState("SAGA-002");
        assertEquals("IN_PROGRESS", state.getStatus());
        state.setStatus("COMPENSATED");
        assertEquals("COMPENSATED", state.getStatus());
    }
}

