@Service class CheckoutSagaOrchestrator {
    private final MockInventory inv;
    private final MockOrderSvc ord;
    private final MockPaySvc pay;
    CheckoutSagaOrchestrator(MockInventory i,MockOrderSvc o,MockPaySvc p){inv=i;ord=o;pay=p;}

    public String execute(CheckoutRequest req){
        SagaState state=new SagaState(req.orderId());
        try{
            inv.reserve(req.itemId()); state.mark(SagaStep.INVENTORY_RESERVED);
            if(req.failAtStep()==false&&req.orderId().contains("FAIL2")) throw new RuntimeException("Order svc down");
            ord.create(req.orderId()); state.mark(SagaStep.ORDER_CREATED);
            if(req.orderId().contains("FAIL3")) throw new RuntimeException("Payment svc down");
            pay.charge(req.paymentId()); state.mark(SagaStep.PAYMENT_CHARGED);
            state.setStatus("COMPLETED");
        }catch(Exception e){
            if(state.is(SagaStep.PAYMENT_CHARGED)) pay.refund(req.paymentId());
            if(state.is(SagaStep.ORDER_CREATED)) ord.cancel(req.orderId());
            if(state.is(SagaStep.INVENTORY_RESERVED)) inv.release(req.itemId());
            state.setStatus("COMPENSATED");
        }
        return state.getStatus();
    }
}

