@DataJpaTest
class SagaLogTest {
    @Autowired SagaLogRepo repo;

    @Test void log_tracksProgress(){
        String sid="SAGA-LOG-001";
        // Simulate saga execution:
        repo.save(new SagaLogEntry(sid,"INVENTORY_RESERVE","STARTED"));
        repo.save(new SagaLogEntry(sid,"INVENTORY_RESERVE","COMPLETED"));
        repo.save(new SagaLogEntry(sid,"ORDER_CREATE","STARTED"));
        // Crash here! On restart:
        List<SagaLogEntry> log=repo.findBySagaIdOrderByAtAsc(sid);
        assertEquals(3,log.size());
        // Recovery logic: ORDER_CREATE started but no COMPLETED → compensate from INVENTORY
        boolean orderCompleted=log.stream()
            .anyMatch(e->e.getStepName().equals("ORDER_CREATE")&&e.getStatus().equals("COMPLETED"));
        assertFalse(orderCompleted); // crashed before ORDER_CREATE completed
    }

