        String sid="SAGA-LOG-002";
        repo.save(new SagaLogEntry(sid,"PAYMENT_CHARGE","STARTED"));
        repo.save(new SagaLogEntry(sid,"PAYMENT_CHARGE","COMPLETED"));
        List<SagaLogEntry> entries=repo.findBySagaIdAndStepName(sid,"PAYMENT_CHARGE");
        assertTrue(entries.stream().anyMatch(e->e.getStatus().equals("COMPLETED")));
    }
}

