import java.util.*;
import org.springframework.boot.test.context.SpringBootTest;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

public enum SagaStatus {
    CREATED, INVENTORY_RESERVED, ORDER_CREATED, PAYMENT_CHARGED,
    COMPLETED, COMPENSATING, COMPENSATED, FAILED
}

public class SagaStateMachine {
    private static final Map<SagaStatus, Set<SagaStatus>> ALLOWED = Map.of(
        SagaStatus.CREATED, Set.of(SagaStatus.INVENTORY_RESERVED, SagaStatus.COMPENSATING),
        SagaStatus.INVENTORY_RESERVED, Set.of(SagaStatus.ORDER_CREATED, SagaStatus.COMPENSATING),
        SagaStatus.ORDER_CREATED, Set.of(SagaStatus.PAYMENT_CHARGED, SagaStatus.COMPENSATING),
        SagaStatus.PAYMENT_CHARGED, Set.of(SagaStatus.COMPLETED, SagaStatus.COMPENSATING),
        SagaStatus.COMPENSATING, Set.of(SagaStatus.COMPENSATED, SagaStatus.FAILED),
        SagaStatus.COMPLETED, Set.of(),
        SagaStatus.COMPENSATED, Set.of(),
        SagaStatus.FAILED, Set.of()
    );

    private SagaStatus current;
    public SagaStateMachine() { current = SagaStatus.CREATED; }

    public void transition(SagaStatus next) {
        Set<SagaStatus> allowed = ALLOWED.getOrDefault(current, Set.of());
        if (!allowed.contains(next))
            throw new IllegalStateException("Cannot transition from "+current+" to "+next);
        current = next;
    }
    public SagaStatus getStatus() { return current; }
}

@SpringBootTest
class SagaStateMachineTest {
    @Test void validForwardPath(){
        SagaStateMachine sm=new SagaStateMachine();
        sm.transition(SagaStatus.INVENTORY_RESERVED);
        sm.transition(SagaStatus.ORDER_CREATED);
        sm.transition(SagaStatus.PAYMENT_CHARGED);
        sm.transition(SagaStatus.COMPLETED);
        assertEquals(SagaStatus.COMPLETED,sm.getStatus());
    }
    @Test void invalidTransition_throws(){
        SagaStateMachine sm=new SagaStateMachine();
        // Can't skip INVENTORY_RESERVED:
        assertThrows(IllegalStateException.class,()->sm.transition(SagaStatus.ORDER_CREATED));
    }
    @Test void compensationPath(){
        SagaStateMachine sm=new SagaStateMachine();
        sm.transition(SagaStatus.INVENTORY_RESERVED);
        sm.transition(SagaStatus.COMPENSATING); // failure after step 1
        sm.transition(SagaStatus.COMPENSATED);
        assertEquals(SagaStatus.COMPENSATED,sm.getStatus());
    }
}

