@Entity @Table(name="checkout_saga_log")
class CheckoutSagaLog {
    @Id @GeneratedValue Long id;
    String sagaId,step,status;
    CheckoutSagaLog(){}
    CheckoutSagaLog(String s,String step,String status){sagaId=s;this.step=step;this.status=status;}
}
interface CheckoutSagaLogRepo extends JpaRepository<CheckoutSagaLog,Long>{
    List<CheckoutSagaLog> findBySagaId(String sagaId);
}

@Service class CompleteCheckoutSaga {
    private final CheckoutSagaLogRepo log;
    Map<String,Boolean> invState=new HashMap<>(), ordState=new HashMap<>(), payState=new HashMap<>();
    CompleteCheckoutSaga(CheckoutSagaLogRepo l){log=l;}

    public String execute(String sagaId,String itemId,String orderId,String payId,int failAt){
        SagaState st=new SagaState(sagaId);
        try{
            log.save(new CheckoutSagaLog(sagaId,"INV","STARTED"));
            invState.put(itemId,true);
            log.save(new CheckoutSagaLog(sagaId,"INV","DONE")); st.mark(SagaStep.INVENTORY_RESERVED);
            if(failAt==2) throw new RuntimeException("order svc down");
            log.save(new CheckoutSagaLog(sagaId,"ORD","STARTED"));
            ordState.put(orderId,true);
            log.save(new CheckoutSagaLog(sagaId,"ORD","DONE")); st.mark(SagaStep.ORDER_CREATED);
            if(failAt==3) throw new RuntimeException("pay svc down");
            payState.put(payId,true);
            st.mark(SagaStep.PAYMENT_CHARGED);
            return "COMPLETED";
        }catch(Exception e){
            if(st.is(SagaStep.PAYMENT_CHARGED)&&!payState.getOrDefault(payId+"_refunded",false)){payState.put(payId,false);payState.put(payId+"_refunded",true);}
            if(st.is(SagaStep.ORDER_CREATED)){ordState.put(orderId,false);}
            if(st.is(SagaStep.INVENTORY_RESERVED)){invState.put(itemId,false);}
            return "COMPENSATED";
        }
    }
}

@SpringBootTest
class CompleteCheckoutSagaTest {
    @Autowired CompleteCheckoutSaga saga;
    @Test void success_completed(){assertEquals("COMPLETED",saga.execute("S1","ITEM-1","ORD-1","PAY-1",0));}
    @Test void step2Fail_inventoryCompensated(){
        saga.execute("S2","ITEM-2","ORD-2","PAY-2",2);
        assertFalse(saga.invState.get("ITEM-2")); // released
    }
    @Test void step3Fail_orderAndInventoryCompensated(){
        saga.execute("S3","ITEM-3","ORD-3","PAY-3",3);
        assertFalse(saga.ordState.get("ORD-3")); // cancelled
        assertFalse(saga.invState.get("ITEM-3")); // released
    }
}

import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service
class IdempotentPaymentGateway {
    private final Map<String, String> processed = new HashMap<>();

    // idempotencyKey: same key on retry → return same result (don't charge twice)
    public String charge(String merchantId, long amountPaise, String idempotencyKey) {
        if (processed.containsKey(idempotencyKey)) {
            return processed.get(idempotencyKey); // duplicate: return original result
        }
        String paymentId = "PAY-" + System.nanoTime();
        processed.put(idempotencyKey, paymentId);
        return paymentId;
    }

    public boolean refund(String paymentId) {
        // Check if already refunded:
        if (processed.containsValue("REFUNDED-" + paymentId)) return true;
        processed.put("refund-" + paymentId, "REFUNDED-" + paymentId);
        return true;
    }

    public int chargeCount(String idempotencyKey) {
        // How many times was this idempotency key submitted?
        return processed.containsKey(idempotencyKey) ? 1 : 0; // deduped to 1
    }
}

// AT-MOST-ONCE vs AT-LEAST-ONCE:
// At-most-once: send payment request once — if no response, don't retry (may miss)
// At-least-once: retry until success — must have idempotency to avoid double charge
// For payments: ALWAYS use at-least-once + idempotency key
// Without idempotency key + retry: customer charged twice on network timeout!

@SpringBootTest
class IdempotentGatewayTest {
    @Autowired IdempotentPaymentGateway gateway;

    @Test void sameIdempKey_processedOnce(){
        String key="IDEM-"+UUID.randomUUID();
        String result1=gateway.charge("MRC-001",50000L,key);
        String result2=gateway.charge("MRC-001",50000L,key); // retry
        assertEquals(result1,result2); // same paymentId returned
        assertEquals(1,gateway.chargeCount(key)); // processed once
    }
    @Test void differentIdempKey_processedSeparately(){
        String r1=gateway.charge("MRC-001",50000L,"KEY-A");
        String r2=gateway.charge("MRC-001",50000L,"KEY-B");
        assertNotEquals(r1,r2); // different payments
    }
}

