@Service
class KafkaInventoryService {
    List<String> reserved=new ArrayList<>();
    List<String> released=new ArrayList<>();
    private final KafkaTemplate<String,String> kafka;
    private final ObjectMapper mapper;
    KafkaInventoryService(KafkaTemplate<String,String> k,ObjectMapper m){kafka=k;mapper=m;}
    // @KafkaListener(topics='orders',groupId='inventory-svc')
    public void onOrderCreated(String json) throws Exception {
        KOrderCreated e=mapper.readValue(json,KOrderCreated.class);
        reserved.add(e.itemId());
        kafka.send("inventory",e.orderId(),
            mapper.writeValueAsString(new KInventoryReserved(e.orderId(),e.itemId(),e.paymentId())));
    }
    // @KafkaListener(topics='payments.failed',groupId='inventory-svc')
    public void onPaymentFailed(String json) throws Exception {
        KPaymentFailed e=mapper.readValue(json,KPaymentFailed.class);
        reserved.remove(e.itemId()); released.add(e.itemId());
    }
}

