@Service
public class MonitoredSagaOrchestrator {
    private final MeterRegistry metrics;

    MonitoredSagaOrchestrator(MeterRegistry m) { metrics = m; }

    public String execute(String sagaId, boolean shouldFail) {
        var timer = Timer.start(metrics);
        String outcome;
        try {
            // Step 1: inventory
            executeStep(sagaId, "INVENTORY", shouldFail && sagaId.contains("FAIL1"));
            // Step 2: order
            executeStep(sagaId, "ORDER", shouldFail && sagaId.contains("FAIL2"));
            outcome = "success";
        } catch (Exception e) {
            // Record compensation:
            Counter.builder("saga.compensation.triggered")
                .tag("step", e.getMessage())
                .register(metrics).increment();
            outcome = "compensated";
        }
        timer.stop(Timer.builder("saga.duration").register(metrics));
        Counter.builder("saga.completed").tag("outcome", outcome).register(metrics).increment();
        return outcome;
    }

    private void executeStep(String sagaId, String step, boolean fail) {
        if (fail) throw new RuntimeException(step);
    }
}

