import org.springframework.stereotype.*;
import io.micrometer.core.instrument.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.beans.factory.annotation.Autowired;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

@Service class SynthSaga {
    private final MeterRegistry metrics;
    Set<String> reserved=new HashSet<>();
    Set<String> released=new HashSet<>();
    Set<String> orders=new HashSet<>();
    Set<String> cancelledOrders=new HashSet<>();

    SynthSaga(MeterRegistry m){metrics=m;}

    public String execute(String orderId,String itemId,int failAt){
        SagaState st=new SagaState(orderId);
        String outcome;
        try{
            reserved.add(itemId); st.mark(SagaStep.INVENTORY_RESERVED);
            if(failAt==2) throw new RuntimeException("ord fail");
            orders.add(orderId); st.mark(SagaStep.ORDER_CREATED);
            if(failAt==3) throw new RuntimeException("pay fail");
            outcome="success";
        }catch(Exception e){
            if(st.is(SagaStep.ORDER_CREATED)&&!cancelledOrders.contains(orderId)){cancelledOrders.add(orderId);orders.remove(orderId);}
            if(st.is(SagaStep.INVENTORY_RESERVED)&&!released.contains(itemId)){released.add(itemId);reserved.remove(itemId);}
            outcome="compensated";
        }
        Counter.builder("saga.completed").tag("outcome",outcome).register(metrics).increment();
        return outcome;
    }

    public String compensateIdempotent(String orderId,String itemId){
        // Idempotent: second call is no-op
        boolean orderCancelled=cancelledOrders.contains(orderId);
        boolean inventoryReleased=released.contains(itemId);
        if(!orderCancelled){cancelledOrders.add(orderId);}
        if(!inventoryReleased){released.add(itemId);}
        return orderCancelled&&inventoryReleased?"ALREADY_DONE":"COMPENSATED";
    }
}

@SpringBootTest
class M24T3SynthesisTest {
    @Autowired SynthSaga saga;
    @Autowired MeterRegistry registry;

    @Test void success_allSteps(){
        assertEquals("success",saga.execute("ORD-S1","ITEM-S1",0));
        assertTrue(saga.reserved.contains("ITEM-S1"));
    }
    @Test void step2Fail_inventoryCompensated(){
        saga.execute("ORD-S2","ITEM-S2",2);
        assertTrue(saga.released.contains("ITEM-S2"));
        assertFalse(saga.reserved.contains("ITEM-S2"));
    }
    @Test void idempotentCompensation_noDoubleRelease(){
        saga.reserved.add("ITEM-S3");
        String r1=saga.compensateIdempotent("ORD-S3","ITEM-S3");
        String r2=saga.compensateIdempotent("ORD-S3","ITEM-S3"); // second call
        assertEquals("COMPENSATED",r1);
        assertEquals("ALREADY_DONE",r2); // idempotent!
    }
    @Test void metrics_recordOutcome(){
        saga.execute("ORD-S4","ITEM-S4",0); // success
        saga.execute("ORD-S5","ITEM-S5",2); // compensated
        double succ=registry.counter("saga.completed","outcome","success").count();
        double comp=registry.counter("saga.completed","outcome","compensated").count();
        assertTrue(succ>=1);assertTrue(comp>=1);
    }
}
